import { useEffect, useState } from 'react';
import api from '../../services/api';
import ProductoForm from './ProductoForm';
import toast from 'react-hot-toast';
import { FiPlus, FiSearch, FiX, FiEdit2, FiToggleLeft, FiToggleRight, FiTrash2, FiAlertCircle } from 'react-icons/fi';
import { motion } from 'framer-motion';

export default function ProductoList() {
  const [productos, setProductos] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editingProducto, setEditingProducto] = useState(null);
  const [termino, setTermino] = useState('');
  const [loading, setLoading] = useState(true);

  const fetchProductos = async () => {
    try {
      const res = await api.get('/productos');
      setProductos(res.data);
    } catch (error) {
      toast.error('Error al cargar productos');
    } finally {
      setLoading(false);
    }
  };

  const buscarProductos = async () => {
    if (!termino.trim()) return fetchProductos();
    try {
      const res = await api.get(`/productos/buscar?termino=${termino}`);
      setProductos(res.data);
    } catch (error) {
      toast.error('Error en búsqueda');
    }
  };

  useEffect(() => {
    fetchProductos();
  }, []);

  const handleToggleActivo = async (id, activoActual) => {
    try {
      await api.patch(`/productos/${id}/toggle-activo`, { activo: !activoActual });
      toast.success(`Producto ${!activoActual ? 'activado' : 'desactivado'}`);
      fetchProductos();
    } catch (error) {
      toast.error('Error al cambiar estado');
    }
  };

  const handleEdit = (producto) => {
    setEditingProducto(producto);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('¿Eliminar producto permanentemente? Esta acción no se puede deshacer.')) {
      try {
        await api.delete(`/productos/${id}`);
        toast.success('Producto eliminado');
        fetchProductos();
      } catch (error) {
        toast.error('Error al eliminar');
      }
    }
  };

  const handleFormClose = () => {
    setShowForm(false);
    setEditingProducto(null);
    fetchProductos();
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="relative">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold bg-gradient-to-r from-primary-600 to-purple-600 bg-clip-text text-transparent">
            📦 Catálogo de Productos
          </h1>
          <p className="text-gray-500 mt-1">Gestiona el inventario y precios de tus productos</p>
        </div>
        <motion.button
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
          onClick={() => setShowForm(true)}
          className="btn-primary flex items-center space-x-2"
        >
          <FiPlus /> <span>Nuevo Producto</span>
        </motion.button>
      </div>
      
      <div className="flex flex-col sm:flex-row gap-4">
        <div className="flex-1 relative">
          <FiSearch className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
          <input
            type="text"
            placeholder="Buscar por nombre o código..."
            value={termino}
            onChange={e => setTermino(e.target.value)}
            onKeyPress={e => e.key === 'Enter' && buscarProductos()}
            className="input-modern pl-10"
          />
        </div>
        <div className="flex gap-2">
          <motion.button whileHover={{ scale: 1.05 }} onClick={buscarProductos} className="btn-primary">
            Buscar
          </motion.button>
          <motion.button whileHover={{ scale: 1.05 }} onClick={fetchProductos} className="btn-secondary flex items-center space-x-1">
            <FiX /> <span>Limpiar</span>
          </motion.button>
        </div>
      </div>
      
      <div className="table-premium">
        <table className="min-w-full">
          <thead>
            <tr>
              <th>Código</th>
              <th>Nombre</th>
              <th>Precio Venta</th>
              <th>Stock</th>
              <th>Estado</th>
              <th>Acciones</th>
            </tr>
          </thead>
          <tbody>
            {productos.map(p => (
              <motion.tr
                key={p.id}
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ duration: 0.3 }}
              >
                <td className="px-6 py-4 font-mono text-sm">{p.codigo}</td>
                <td className="px-6 py-4 font-medium">{p.nombre}</td>
                <td className="px-6 py-4 text-green-600 font-semibold">${parseFloat(p.precio_venta).toFixed(2)}</td>
                <td className="px-6 py-4">
                  <span className={p.stock_actual <= p.stock_minimo ? 'badge-danger' : 'badge-success'}>
                    {p.stock_actual} unidades
                  </span>
                </td>
                <td className="px-6 py-4">
                  <span className={p.activo ? 'badge-success' : 'badge-danger'}>
                    {p.activo ? 'Activo' : 'Inactivo'}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex space-x-3">
                    <button onClick={() => handleEdit(p)} className="text-blue-600 hover:text-blue-800 transition-colors" title="Editar">
                      <FiEdit2 />
                    </button>
                    <button onClick={() => handleToggleActivo(p.id, p.activo)} className="text-yellow-600 hover:text-yellow-800 transition-colors" title={p.activo ? 'Desactivar' : 'Activar'}>
                      {p.activo ? <FiToggleRight className="text-xl" /> : <FiToggleLeft className="text-xl" />}
                    </button>
                    <button onClick={() => handleDelete(p.id)} className="text-red-600 hover:text-red-800 transition-colors" title="Eliminar">
                      <FiTrash2 />
                    </button>
                  </div>
                </td>
               </motion.tr>
            ))}
          </tbody>
        </table>
        {productos.length === 0 && (
          <div className="text-center py-12">
            <FiAlertCircle className="text-4xl text-gray-400 mx-auto mb-3" />
            <p className="text-gray-500">No se encontraron productos</p>
          </div>
        )}
      </div>
      
      {showForm && (
        <ProductoForm producto={editingProducto} onClose={handleFormClose} />
      )}
    </div>
  );
}
